196→.toolPaletteBtn {
197→  display: flex;
198→  align-items: center;
199→  justify-content: center;
200→  width: 34px;
201→  height: 34px;
202→  border-radius: var(--radius-sm);
203→  border: 1px solid transparent;
204→  color: var(--color-text-secondary);
205→  transition: background var(--duration-fast), color var(--duration-fast), border-color var(--duration-fast), transform var(--duration-micro) var(--ease-tactile), box-shadow var(--duration-fast);
206→  position: relative;
207→  cursor: pointer;
208→}
209→
210→.toolPaletteBtn:hover {
211→  background: rgba(0, 0, 0, 0.04);
212→  border-color: rgba(0, 0, 0, 0.06);
213→  color: var(--color-text-primary);
214→  transform: translateY(-1px);
215→  box-shadow: var(--shadow-sm);
216→}
217→
218→.toolPaletteBtn:active {
