 60→
 61→function screenToModel(screenX, screenY, viewport, svgRect) {
 62→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 63→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 64→  return { x, y };
 65→}
 66→
 67→export default function SvgCanvas() {
 68→  const svgRef = useRef(null);
 69→  const isPanning = useRef(false);
 70→  const lastPanPos = useRef({ x: 0, y: 0 });
 71→  const spaceHeld = useRef(false);
 72→  const cursorPosRef = useRef({ x: 0, y: 0 });
 73→  const [cursorPos, setCursorPos] = useState({ x: 0, y: 0 });
 74→
 75→  const { project, dispatch, getFloor } = useProject();
 76→  const editor = useEditor();
 77→  const {
 78→    activeTool, selectedId, selectedType, toolState,
 79→    viewport, showGrid, snapEnabled, activeFloorId, statusMessage, viewMode, activeSectionCutId,
 80→    regionSelection, pastePreview, maximizedPanel,
 81→    modelTarget,
 82→    activePhaseId, phaseViewMode,
 83→    dispatch: editorDispatch,
 84→  } = editor;
 85→
 86→  const floor = getFloor(activeFloorId);
 87→  const filteredFloor = usePhaseFilteredFloor(floor, project, activePhaseId, phaseViewMode);
 88→  const filteredProject = useMemo(
 89→    () => filterProjectByPhase(project, activePhaseId, phaseViewMode),
 90→    [project, activePhaseId, phaseViewMode]
 91→  );
 92→  const roofSystem = filteredProject.roofSystem || null;
 93→  const roofHiddenByPhase = Boolean(project.roofSystem && !roofSystem);
 94→  const floorTrussSystems = (filteredProject.trussSystems || []).filter((trussSystem) => trussSystem.floorId === activeFloorId);
 95→  const activeTrussContext = useMemo(() => {
 96→    if (selectedType === 'trussSystem') {
 97→      const trussSystem = (filteredProject.trussSystems || []).find((entry) => entry.id === selectedId) || null;
 98→      return {
 99→        trussSystem,
100→        trussInstanceId: null,
101→      };
102→    }
103→    if (selectedType === 'trussInstance') {
104→      const trussSystem = (filteredProject.trussSystems || []).find((entry) => (
105→        (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
106→      )) || null;
107→      return {
108→        trussSystem,
109→        trussInstanceId: selectedId,
110→      };
111→    }
112→    return {
113→      trussSystem: floorTrussSystems[0] || null,
114→      trussInstanceId: floorTrussSystems[0]?.trussInstances?.[0]?.id || null,
115→    };
116→  }, [filteredProject.trussSystems, floorTrussSystems, selectedId, selectedType]);
117→  const {
118→    copySelection,
119→    cutSelection,
120→    beginPaste,
121→    updatePastePreview,
122→    cancelPaste,
123→    placePaste,
124→    previewContent,
125→  } = usePlanClipboardController();
126→
127→  const tool = useEditorTool({
128→    activeTool,
129→    dispatch,
130→    editorDispatch,
131→    project,
132→    getFloor,
133→    activeFloorId,
134→    roofSystem,
135→    trussSystems: floorTrussSystems,
136→    modelTarget,
137→    viewport,
138→    snapEnabled,
139→    selectedId,
140→    selectedType,
141→    toolState,
142→    viewMode,
143→    activePhaseId,
144→  });
145→
146→  const getModelPos = useCallback((e) => {
147→    const rect = svgRef.current.getBoundingClientRect();
148→    return screenToModel(e.clientX, e.clientY, viewport, rect);
149→  }, [viewport]);
150→
151→  const handleMouseDown = useCallback((e) => {
152→    // Middle mouse or space+left for pan
153→    if (e.button === 1 || (e.button === 0 && spaceHeld.current)) {
154→      isPanning.current = true;
155→      lastPanPos.current = { x: e.clientX, y: e.clientY };
156→      e.preventDefault();
157→      return;
158→    }
159→
160→    const modelPos = getModelPos(e);
161→    if (modelTarget === 'floor' && pastePreview?.active && e.button === 0) {
162→      placePaste(modelPos);
163→      return;
164→    }
165→    tool.onMouseDown(modelPos, e);
166→  }, [getModelPos, modelTarget, pastePreview, placePaste, tool]);
167→
168→  const handleMouseMove = useCallback((e) => {
169→    if (isPanning.current) {
170→      const dx = e.clientX - lastPanPos.current.x;
171→      const dy = e.clientY - lastPanPos.current.y;
172→      editorDispatch({ type: 'PAN', dx, dy });
173→      lastPanPos.current = { x: e.clientX, y: e.clientY };
174→      return;
175→    }
176→
177→    const modelPos = getModelPos(e);
178→    cursorPosRef.current = modelPos;
179→    setCursorPos(modelPos);
180→    if (modelTarget === 'floor' && pastePreview?.active) {
181→      updatePastePreview(modelPos);
182→      return;
183→    }
184→    tool.onMouseMove(modelPos, e);
185→  }, [getModelPos, modelTarget, pastePreview, tool, updatePastePreview, editorDispatch]);
186→
187→  const handleMouseUp = useCallback((e) => {
188→    if (isPanning.current) {
189→      isPanning.current = false;
190→      return;
191→    }
192→    if (modelTarget === 'floor' && pastePreview?.active) return;
193→    const modelPos = getModelPos(e);
194→    tool.onMouseUp(modelPos, e);
195→  }, [getModelPos, modelTarget, pastePreview, tool]);
196→
197→  const handleDoubleClick = useCallback((e) => {
198→    if (modelTarget === 'floor' && pastePreview?.active) return;
199→    const modelPos = getModelPos(e);
200→    tool.onDoubleClick(modelPos, e);
201→  }, [getModelPos, modelTarget, pastePreview, tool]);
202→
203→  const handleWheel = useCallback((e) => {
204→    e.preventDefault();
205→    const rect = svgRef.current.getBoundingClientRect();
206→    const mouseX = e.clientX - rect.left;
207→    const mouseY = e.clientY - rect.top;
208→
209→    const direction = e.deltaY < 0 ? 1 : -1;
210→    const factor = direction > 0 ? ZOOM_FACTOR : 1 / ZOOM_FACTOR;
211→    const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, viewport.zoom * factor));
212→
213→    // Zoom centered on cursor
214→    const newPanX = mouseX - (mouseX - viewport.panX) * (newZoom / viewport.zoom);
215→    const newPanY = mouseY - (mouseY - viewport.panY) * (newZoom / viewport.zoom);
216→
217→    editorDispatch({ type: 'ZOOM', zoom: newZoom, panX: newPanX, panY: newPanY });
218→  }, [viewport, editorDispatch]);
219→
220→  const handleResetCenterPoint = useCallback(() => {
221→    const rect = svgRef.current?.getBoundingClientRect();
222→    if (!rect) return;
223→
224→    editorDispatch({
225→      type: 'SET_VIEWPORT',
226→      viewport: {
227→        ...viewport,
228→        panX: rect.width / 2,
229→        panY: rect.height / 2,
230→      },
231→    });
232→  }, [editorDispatch, viewport]);
233→
234→  useEffect(() => {
235→    if (!statusMessage) return undefined;
236→
237→    const timer = window.setTimeout(() => {
238→      editorDispatch({ type: 'CLEAR_STATUS_MESSAGE' });
239→    }, 2500);
240→
241→    return () => window.clearTimeout(timer);
242→  }, [statusMessage, editorDispatch]);
243→
244→  useEffect(() => {
245→    const handleKeyDown = (e) => {
246→      if (isTypingTarget(e.target)) return;
247→
248→      if (e.key === ' ') {
249→        spaceHeld.current = true;
250→        e.preventDefault();
251→      }
252→
253→      if ((e.ctrlKey || e.metaKey) && viewMode === 'plan' && modelTarget === 'floor') {
254→        const key = e.key.toLowerCase();
255→        if (key === 'c') {
256→          e.preventDefault();
257→          copySelection();
258→          return;
259→        }
260→        if (key === 'x') {
261→          e.preventDefault();
262→          cutSelection();
263→          return;
264→        }
265→        if (key === 'v') {
266→          e.preventDefault();
267→          beginPaste(cursorPosRef.current);
268→          return;
269→        }
270→      }
271→
272→      if (e.key === 'Escape' && modelTarget === 'floor' && pastePreview?.active) {
273→        e.preventDefault();
274→        cancelPaste();
275→        return;
276→      }
277→
278→      // Tool shortcuts
279→      if (viewMode === 'plan' && !e.ctrlKey && !e.metaKey) {
280→        if (modelTarget === 'roof') {
281→          switch (e.key.toLowerCase()) {
282→            case 'v':
283→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
284→              return;
285→            case 'p':
286→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_PARAPET });
287→              return;
288→            case 'g':
289→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_DRAIN });
290→              return;
291→            case 'o':
292→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOF_OPENING });
293→              return;
294→          }
295→        } else if (modelTarget === 'truss') {
296→          switch (e.key.toLowerCase()) {
297→            case 'v':
298→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
299→              return;
300→            case 't': {
301→              const targetTrussSystem = selectedType === 'trussSystem'
302→                ? floorTrussSystems.find((entry) => entry.id === selectedId) || null
303→                : selectedType === 'trussInstance'
304→                  ? floorTrussSystems.find((entry) => (
305→                      (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
306→                    )) || null
307→                  : null;
308→              const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
309→                ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
310→                : null;
311→              const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
312→                ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
313→                : null;
314→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.TRUSS_DRAW });
315→              editorDispatch({
316→                type: 'UPDATE_TOOL_STATE',
317→                payload: {
318→                  targetTrussSystemId: targetTrussSystem?.id || null,
319→                  trussTypeId: selectedTrussInstance?.trussTypeId
320→                    || lastSystemInstance?.trussTypeId
321→                    || null,
322→                  trussMaterial: selectedTrussInstance?.material
323→                    || lastSystemInstance?.material
324→                    || null,
325→                },
326→              });
327→              return;
328→            }
329→          }
330→        } else {
331→          switch (e.key.toLowerCase()) {
332→            case 'v':
333→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SELECT });
334→              return;
335→            case 'm':
336→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DIMENSION });
337→              return;
338→            case 'w':
339→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WALL });
340→              return;
341→            case 'b':
342→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.BEAM });
343→              return;
344→            case 't':
345→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.STAIR });
346→              return;
347→            case 'q':
348→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SECTION });
349→              return;
350→            case 's':
351→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.SLAB });
352→              return;
353→            case 'r':
354→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.ROOM });
355→              return;
356→            case 'd':
357→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.DOOR });
358→              return;
359→            case 'n':
360→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.WINDOW });
361→              return;
362→            case 'c':
363→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.COLUMN });
364→              return;
365→            case 'l':
366→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.LANDING });
367→              return;
368→            case 'h':
369→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.RAILING });
370→              return;
371→            case 'f':
372→              editorDispatch({ type: 'SET_TOOL', tool: TOOLS.FIXTURE });
373→              editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { fixtureType: 'kitchenTop', previewRotation: 0 } });
374→              return;
375→          }
376→        }
377→      }
378→
379→      tool.onKeyDown(e);
380→    };
381→
382→    const handleKeyUp = (e) => {
383→      if (isTypingTarget(e.target)) return;
384→
385→      if (e.key === ' ') {
386→        spaceHeld.current = false;
387→      }
388→    };
389→
390→    window.addEventListener('keydown', handleKeyDown);
391→    window.addEventListener('keyup', handleKeyUp);
392→    return () => {
393→      window.removeEventListener('keydown', handleKeyDown);
394→      window.removeEventListener('keyup', handleKeyUp);
395→    };
396→  }, [beginPaste, cancelPaste, copySelection, cutSelection, modelTarget, pastePreview?.active, tool, editorDispatch, viewMode, selectedId, selectedType, floorTrussSystems]);
397→
398→  // Prevent default context menu on SVG
399→  useEffect(() => {
400→    const svg = svgRef.current;
401→    if (!svg) return;
402→    const prevent = (e) => e.preventDefault();
403→    svg.addEventListener('contextmenu', prevent);
404→    svg.addEventListener('wheel', handleWheel, { passive: false });
405→    return () => {
406→      svg.removeEventListener('contextmenu', prevent);
407→      svg.removeEventListener('wheel', handleWheel);
408→    };
409→  }, [handleWheel]);
410→
411→  const cursor = spaceHeld.current ? 'grab' : (modelTarget === 'floor' && pastePreview?.active) ? 'copy' : tool.getCursor();
412→  const zoomPercent = Math.round(viewport.zoom * 1000);
413→  const displayedTool = viewMode.startsWith('elevation_') ? 'select' : activeTool;
414→  const isCanvasMaximized = maximizedPanel === 'canvas';
415→  const marqueeBounds = toolState.dragType === 'marquee' && toolState.startPos && toolState.currentPos
416→    ? normalizeRectBounds(toolState.startPos, toolState.currentPos)
417→    : null;
418→  const selectionCount = regionSelection?.objectCount || 0;
419→  const liveWallBearing = modelTarget === 'floor' && activeTool === TOOLS.WALL && toolState.start && toolState.preview
420→    ? formatSurveyorBearing(pointsToSurveyorBearing(toolState.start, toolState.preview))
421→    : null;
422→  const hasRoofSectionCut = Boolean(resolveRoofSectionCut(project, activeFloorId, activeSectionCutId).sectionCut);
423→  const hasTrussSectionCut = Boolean((floor?.sectionCuts || []).length);
424→
425→  return (
426→    <div className={styles.canvasContainer}>
427→      <CompassOverlay className={styles.compassDock} />
428→      <svg
429→        ref={svgRef}
430→        className={styles.svg}
431→        style={{ cursor }}
432→        onMouseDown={handleMouseDown}
433→        onMouseMove={handleMouseMove}
434→        onMouseUp={handleMouseUp}
435→        onDoubleClick={handleDoubleClick}
436→      >
437→        <g transform={`translate(${viewport.panX}, ${viewport.panY}) scale(${viewport.zoom})`}>
438→          {viewMode === 'plan' && showGrid && <GridRenderer />}
439→          {viewMode === 'plan' && showGrid && (
440→            <rect
441→              x={-100000} y={-100000}
442→              width={200000} height={200000}
443→              fill="url(#grid-major)"
444→              style={{ pointerEvents: 'none' }}
445→            />
446→          )}
447→          {modelTarget === 'roof' ? (
448→            roofSystem ? (
449→              <>
450→                {viewMode === 'plan' ? (
451→                  <>
452→                    <RoofRenderer roofSystem={roofSystem} selectedId={selectedId} selectedType={selectedType} />
453→                    <RoofSelectionOverlay
454→                      roofSystem={roofSystem}
455→                      selectedId={selectedId}
456→                      selectedType={selectedType}
457→                      zoom={viewport.zoom}
458→                    />
459→                    <RoofPreviewLayer activeTool={activeTool} toolState={toolState} roofSystem={roofSystem} />
460→                  </>
461→                ) : viewMode === 'section_view' ? (
462→                  <RoofSectionRenderer
463→                    project={filteredProject}
