683→        <span>Y: {Math.round(cursorPos.y)} mm</span>
684→        <span>Zoom: {zoomPercent}%</span>
685→        <span>View: {viewMode}</span>
686→        <span>Mode: {modelTarget}</span>
687→        <span>Tool: {displayedTool}</span>
688→        {activePhaseId && (
689→          <span>Phase: {(project.phases || []).find(p => p.id === activePhaseId)?.name || 'Unknown'} ({phaseViewMode})</span>
690→        )}
