  1→import { useState } from 'react';
  2→import { useProject } from '@/app/ProjectProvider';
  3→import { useEditor } from '@/app/EditorProvider';
  4→import { getBeamDisplayLabel } from '@/domain/beamLabels';
  5→import { getColumnListLabel } from '@/domain/columnLabels';
  6→import { createFloorAboveHighest, getFloorElevation, getFloorLevelIndex, getOrderedFloors } from '@/domain/floorModels';
  7→import { createPhase, getNextPhaseOrder, getOrderedPhases, PHASE_COLORS, reorderPhases } from '@/domain/phaseModels';
  8→import { getAttachableRoofTrussSystems, getRoofTypeLabel } from '@/domain/roofModels';
  9→import { TOOLS } from '@/editor/tools';
 10→import { createSheet, getSheetDisplayLabel } from '@/domain/sheetModels';
 11→import { getSlabDisplayLabel } from '@/domain/slabLabels';
 12→import { getStairDisplayLabel } from '@/domain/stairLabels';
 13→import { getLandingDisplayLabel } from '@/domain/landingLabels';
 14→import { getAnnotationDisplayLabel } from '@/annotations/format';
 15→import styles from './Sidebar.module.css';
