 17→function ChevronSvg({ collapsed }) {
 18→  return (
 19→    <span className={`${styles.chevron} ${collapsed ? styles.chevronCollapsed : ''}`}>
 20→      <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.chevronIcon}>
 21→        <path
 22→          d="M5 3.5l4 3.5-4 3.5"
 23→          fill="none"
 24→          stroke="currentColor"
 25→          strokeWidth="1.5"
 26→          strokeLinecap="round"
 27→          strokeLinejoin="round"
 28→        />
 29→      </svg>
 30→    </span>
 31→  );
 32→}
 33→
 34→function DuplicateIcon() {
 35→  return (
 36→    <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
 37→      <rect x="5" y="5" width="7" height="7" rx="1" fill="none" stroke="currentColor" strokeWidth="1.2" />
 38→      <path d="M2 9V3a1 1 0 0 1 1-1h6" fill="none" stroke="currentColor" strokeWidth="1.2" />
 39→    </svg>
 40→  );
 41→}
 42→
 43→function TrashIcon() {
 44→  return (
 45→    <svg viewBox="0 0 14 14" aria-hidden="true" className={styles.floorActionIcon}>
 46→      <path d="M3 4.5h8M5.5 4.5V3a.5.5 0 0 1 .5-.5h2a.5.5 0 0 1 .5.5v1.5" fill="none" stroke="currentColor" strokeWidth="1.2" strokeLinecap="round" />
 47→      <path d="M4 4.5l.5 7.5a.5.5 0 0 0 .5.5h4a.5.5 0 0 0 .5-.5l.5-7.5" fill="none" stroke="currentColor" strokeWidth="1.2" />
 48→    </svg>
 49→  );
 50→}
 51→
 52→function Section({ title, count, collapsed, onToggle, collapsible = true, action, children }) {
 53→  return (
 54→    <div className={styles.section}>
 55→      <div className={styles.sectionHeaderRow}>
 56→        <button
 57→          type="button"
 58→          className={`${styles.sectionHeader} ${collapsible ? styles.sectionHeaderClickable : ''} ${styles.sectionHeaderContent}`}
 59→          onClick={collapsible ? onToggle : undefined}
 60→          aria-expanded={!collapsed}
 61→        >
 62→          {collapsible ? <ChevronSvg collapsed={collapsed} /> : <span style={{ width: 14 }} />}
 63→          <span className={styles.sectionTitle}>{title}</span>
 64→          {count !== undefined && <span className={styles.count}>{count}</span>}
 65→        </button>
 66→        {action}
 67→      </div>
 68→      {!collapsed && children}
 69→    </div>
 70→  );
 71→}
 72→
 73→export default function Sidebar() {
 74→  const { project, dispatch, duplicateFloor } = useProject();
 75→  const { activeFloorId, activeSheetId, selectedId, selectedType, workspaceMode, modelTarget, activePhaseId, phaseViewMode, dispatch: editorDispatch } = useEditor();
 76→  const orderedFloors = getOrderedFloors(project);
 77→  const orderedPhases = getOrderedPhases(project);
 78→  const floor = orderedFloors.find((entry) => entry.id === activeFloorId) || null;
 79→  const roofSystem = project.roofSystem || null;
 80→  const trussSystems = project.trussSystems || [];
 81→  const attachableRoofTrussSystems = getAttachableRoofTrussSystems(project);
 82→  const roofPhase = roofSystem?.phaseId
 83→    ? orderedPhases.find((phase) => phase.id === roofSystem.phaseId) || null
 84→    : null;
 85→  const [collapsedSections, setCollapsedSections] = useState({
 86→    floors: false,
 87→    roof: false,
 88→    roofPlanes: false,
 89→    ridges: false,
 90→    valleys: false,
 91→    hips: false,
 92→    parapets: false,
 93→    drains: false,
 94→    roofOpenings: false,
 95→    trusses: false,
 96→    sheets: false,
 97→    phases: false,
 98→    slabs: false,
 99→    walls: false,
100→    annotations: false,
101→    beams: false,
102→    stairs: false,
103→    landings: false,
104→    doors: false,
105→    windows: false,
106→    columns: false,
107→    rooms: false,
108→  });
109→
110→  const selectObject = (id, type) => {
111→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
112→  };
113→
114→  const selectFloor = (floorId) => {
115→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'floor' });
116→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
117→    editorDispatch({ type: 'SELECT_OBJECT', id: floorId, objectType: 'floor' });
118→  };
119→
120→  const selectRoofObject = (id, type) => {
121→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
122→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
123→  };
124→
125→  const openRoofWorkspace = () => {
126→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'roof' });
127→    editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
128→    if (roofSystem) {
129→      editorDispatch({ type: 'SELECT_OBJECT', id: roofSystem.id, objectType: 'roofSystem' });
130→      return;
131→    }
132→    editorDispatch({ type: 'DESELECT' });
133→  };
134→
135→  const selectTrussObject = (id, type, floorId = null) => {
136→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'truss' });
137→    if (floorId) {
138→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
139→    }
140→    editorDispatch({ type: 'SELECT_OBJECT', id, objectType: type });
141→  };
142→
143→  const setActiveFloor = (floorId) => {
144→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId });
145→  };
146→
147→  const addFloor = () => {
148→    const nextFloor = createFloorAboveHighest(project.floors || []);
149→    dispatch({ type: 'FLOOR_ADD', floor: nextFloor });
150→    selectFloor(nextFloor.id);
151→  };
152→
153→  const handleDuplicateFloor = (floorToDuplicate) => {
154→    const duplicatedFloor = duplicateFloor(floorToDuplicate.id);
155→    if (!duplicatedFloor) return;
156→
157→    dispatch({ type: 'FLOOR_DUPLICATE', floor: duplicatedFloor });
158→    selectFloor(duplicatedFloor.id);
159→  };
160→
161→  const handleDeleteFloor = (floorToDelete) => {
162→    if ((project.floors || []).length <= 1) return;
163→
164→    const confirmed = window.confirm(`Delete "${floorToDelete.name}"?`);
165→    if (!confirmed) return;
166→
167→    const remainingFloors = orderedFloors.filter((entry) => entry.id !== floorToDelete.id);
168→    const fallbackFloor = remainingFloors[0] || null;
169→
170→    dispatch({
171→      type: 'FLOOR_DELETE',
172→      floorId: floorToDelete.id,
173→      fallbackFloorId: fallbackFloor?.id ?? null,
174→    });
175→
176→    if (floorToDelete.id === activeFloorId && fallbackFloor) {
177→      if (workspaceMode === 'model') {
178→        selectFloor(fallbackFloor.id);
179→      } else {
180→        setActiveFloor(fallbackFloor.id);
181→      }
182→    }
183→  };
184→
185→  const addPhase = () => {
186→    const nextOrder = getNextPhaseOrder(project.phases || []);
187→    const color = PHASE_COLORS[nextOrder % PHASE_COLORS.length];
188→    const phase = createPhase(`Phase ${nextOrder + 1}`, nextOrder, color);
189→    dispatch({ type: 'PHASE_ADD', phase });
190→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: phase.id });
191→    editorDispatch({ type: 'SELECT_OBJECT', id: phase.id, objectType: 'phase' });
192→  };
193→
194→  const selectPhase = (phaseId) => {
195→    editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId });
196→    if (phaseViewMode === 'all') {
197→      editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'single' });
198→    }
199→    editorDispatch({ type: 'SELECT_OBJECT', id: phaseId, objectType: 'phase' });
200→  };
201→
202→  const handleDeletePhase = (phase) => {
203→    if (!window.confirm(`Delete phase "${phase.name}"?`)) return;
204→    dispatch({ type: 'PHASE_DELETE', phaseId: phase.id });
205→    if (activePhaseId === phase.id) {
206→      editorDispatch({ type: 'SET_ACTIVE_PHASE', phaseId: null });
207→      editorDispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'all' });
208→    }
209→    editorDispatch({ type: 'DESELECT' });
210→  };
211→
212→  const handleMovePhase = (phase, direction) => {
213→    const newOrder = phase.order + direction;
214→    const reordered = reorderPhases(project.phases || [], phase.id, newOrder);
215→    dispatch({ type: 'PHASE_REORDER', phases: reordered });
216→  };
217→
218→  const handleTogglePhaseVisibility = (phase, e) => {
219→    e.stopPropagation();
220→    dispatch({ type: 'PHASE_UPDATE', phase: { id: phase.id, visible: phase.visible !== false ? false : true } });
221→  };
222→
223→  const addSheet = () => {
224→    const nextIndex = (project.sheets || []).length + 1;
225→    const sheet = createSheet(`Sheet ${nextIndex}`, {
226→      drawingName: `Drawing ${nextIndex}`,
227→      number: `A${String(nextIndex).padStart(2, '0')}`,
228→    });
229→    dispatch({ type: 'SHEET_ADD', sheet });
230→    editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheet.id });
231→    editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' });
232→    editorDispatch({ type: 'SELECT_OBJECT', id: sheet.id, objectType: 'sheet' });
233→  };
234→
235→  const toggleSection = (sectionKey) => {
236→    setCollapsedSections(current => ({
237→      ...current,
238→      [sectionKey]: !current[sectionKey],
239→    }));
240→  };
241→
242→  const createRoof = () => {
243→    openRoofWorkspace();
244→  };
245→
246→  const createTruss = () => {
247→    const targetTrussSystem = selectedType === 'trussSystem'
248→      ? (project.trussSystems || []).find((entry) => entry.id === selectedId) || null
249→      : selectedType === 'trussInstance'
250→        ? (project.trussSystems || []).find((entry) => (
251→            (entry.trussInstances || []).some((trussInstance) => trussInstance.id === selectedId)
252→          )) || null
253→        : null;
254→    const selectedTrussInstance = selectedType === 'trussInstance' && targetTrussSystem
255→      ? (targetTrussSystem.trussInstances || []).find((entry) => entry.id === selectedId) || null
256→      : null;
257→    const lastSystemInstance = targetTrussSystem && (targetTrussSystem.trussInstances || []).length
258→      ? targetTrussSystem.trussInstances[targetTrussSystem.trussInstances.length - 1]
259→      : null;
260→
261→    editorDispatch({ type: 'SET_MODEL_TARGET', modelTarget: 'truss' });
262→    editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: activeFloorId });
263→    editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'plan' });
264→    editorDispatch({ type: 'SET_TOOL', tool: TOOLS.TRUSS_DRAW });
265→    editorDispatch({
266→      type: 'UPDATE_TOOL_STATE',
267→      payload: {
268→        targetTrussSystemId: targetTrussSystem?.id || null,
269→        trussTypeId: selectedTrussInstance?.trussTypeId
270→          || lastSystemInstance?.trussTypeId
271→          || null,
272→        trussMaterial: selectedTrussInstance?.material
273→          || lastSystemInstance?.material
274→          || null,
275→      },
276→    });
277→    editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Select two support beams to create a truss.' });
278→  };
279→
280→  return (
281→    <div className={styles.sidebar}>
282→      <Section title="Project" collapsible={false}>
283→        <input
284→          className={styles.projectName}
285→          value={project.name}
286→          onChange={(e) => dispatch({ type: 'PROJECT_SET_NAME', name: e.target.value })}
287→        />
288→      </Section>
289→
290→      <Section
291→        title="Floors"
292→        count={orderedFloors.length}
293→        collapsed={collapsedSections.floors}
294→        onToggle={() => toggleSection('floors')}
295→        action={
296→          <button type="button" className={styles.sectionAddBtn} onClick={addFloor} title="Add Floor">+</button>
297→        }
298→      >
299→        {orderedFloors.map((entry) => (
300→          <div
301→            key={entry.id}
302→            className={`${styles.floorCard} ${entry.id === activeFloorId ? styles.floorCardActive : ''}`}
303→          >
304→            <button
305→              type="button"
306→              className={styles.floorButton}
307→              onClick={() => selectFloor(entry.id)}
308→            >
309→              <span className={styles.floorName}>{entry.name}</span>
310→              <span className={styles.floorMeta}>
311→                L{getFloorLevelIndex(entry)} · {Math.round(getFloorElevation(entry))} mm
312→              </span>
313→            </button>
314→            <div className={styles.floorActions}>
315→              <button
316→                type="button"
317→                className={styles.floorActionBtn}
318→                onClick={() => handleDuplicateFloor(entry)}
319→                title={`Duplicate ${entry.name}`}
320→              >
321→                <DuplicateIcon />
322→              </button>
323→              <button
324→                type="button"
325→                className={`${styles.floorActionBtn} ${styles.floorActionDanger}`}
326→                onClick={() => handleDeleteFloor(entry)}
327→                title={`Delete ${entry.name}`}
328→                disabled={orderedFloors.length <= 1}
